  'Document interne Propul''seo : 12 contrôles à faire avant tout rendu client (HTTPS, en-têtes, accès, OWASP, dépendances, secrets, email, RGPD, sauvegardes, monitoring, pages erreur). Outils gratuits, seuils de blocage, checklist finale.',
  $proc_securite${"type":"doc","content":[{"type":"heading","attrs":{"level":1},"content":[{"type":"text","text":"🛡️ Guide de sécurité — Propul'seo"}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Comment vérifier qu'un site web est vraiment sécurisé, "},{"type":"text","text":"même quand on n'est pas développeur","marks":[{"type":"bold"}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"Document interne Propul'seo","marks":[{"type":"bold"}]},{"type":"text","text":" · Version 2.0\nPour Lyes, Etienne, et toute personne qui valide un projet avant rendu client."}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"🎯 Pourquoi ce document existe"}]},{"type":"paragraph","content":[{"type":"text","text":"On ne livre "},{"type":"text","text":"jamais","marks":[{"type":"bold"}]},{"type":"text","text":" un site sans avoir vérifié qu'il est sécurisé. Pas par perfectionnisme, mais parce que les chiffres sont sans appel :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"60 % des PME","marks":[{"type":"bold"}]},{"type":"text","text":" victimes d'une cyberattaque majeure déposent le bilan dans les 18 mois (source : ANSSI)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Plus de la moitié des entreprises françaises","marks":[{"type":"bold"}]},{"type":"text","text":" ont subi au moins une cyberattaque en 2023."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"80 % des grandes fuites de données en 2024","marks":[{"type":"bold"}]},{"type":"text","text":" ont été permises par un simple mot de passe sans double authentification (source : CNIL)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Une faille RGPD peut coûter jusqu'à "},{"type":"text","text":"10 millions d'euros ou 2 % du chiffre d'affaires","marks":[{"type":"bold"}]},{"type":"text","text":" au client."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Notre engagement chez Propul'seo :","marks":[{"type":"bold"}]},{"type":"text","text":" quand on livre un site, le client n'a pas à se demander s'il est protégé. Nous l'avons vérifié pour lui."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"📖 Comment lire ce document"}]},{"type":"paragraph","content":[{"type":"text","text":"Chaque test est expliqué en 5 parties :"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"🤔 C'est quoi ?","marks":[{"type":"bold"}]},{"type":"text","text":" — En langage simple, avec une analogie de la vie courante."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"⚠️ Ce qui peut arriver","marks":[{"type":"bold"}]},{"type":"text","text":" — Un scénario réel si on ne fait rien."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"🔍 Comment vérifier","marks":[{"type":"bold"}]},{"type":"text","text":" — L'outil gratuit à utiliser et où cliquer."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"✅ La note minimum","marks":[{"type":"bold"}]},{"type":"text","text":" — Le seuil en-dessous duquel on ne livre pas."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"🛠️ Si problème","marks":[{"type":"bold"}]},{"type":"text","text":" — Qui s'en occupe."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Code couleur"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — Sans ça, le site est en danger immédiat. "},{"type":"text","text":"Blocage du rendu","marks":[{"type":"bold"}]},{"type":"text","text":" tant que ce n'est pas corrigé."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"🟧 "},{"type":"text","text":"IMPORTANT","marks":[{"type":"bold"}]},{"type":"text","text":" — Risque réel mais pas immédiat. À corriger avant rendu sauf justification écrite."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"🟨 "},{"type":"text","text":"RECOMMANDÉ","marks":[{"type":"bold"}]},{"type":"text","text":" — Bonne pratique professionnelle. Idéalement fait, sinon noté dans le rapport."}]}]}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"🗂️ Sommaire"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"La porte d'entrée du site (HTTPS)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les serrures supplémentaires (en-têtes de sécurité)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les mots de passe et accès"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les pirates qui essaient d'entrer (OWASP Top 10)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les pièces détachées du site (dépendances)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les secrets (clés et mots de passe dans le code)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les emails (SPF, DKIM, DMARC)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le RGPD et les cookies"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les sauvegardes (la copie de secours)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"La surveillance (le système d'alarme)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"La page d'erreur (que se passe-t-il quand ça plante ?)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le test final avant rendu"}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"1. La porte d'entrée du site : est-ce qu'on peut écouter aux portes ?"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🤔 C'est quoi ?"}]},{"type":"paragraph","content":[{"type":"text","text":"Quand un visiteur va sur un site, son ordinateur "},{"type":"text","text":"discute","marks":[{"type":"bold"}]},{"type":"text","text":" avec le serveur du site. Il envoie son nom, son adresse, parfois sa carte bancaire. Cette conversation peut se faire de deux façons :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"HTTP","marks":[{"type":"bold"}]},{"type":"text","text":" (sans le S) → c'est comme "},{"type":"text","text":"envoyer une carte postale","marks":[{"type":"bold"}]},{"type":"text","text":". Tout le monde sur le chemin (le facteur, les voisins, le café Wi-Fi) peut lire ce qui est écrit dessus."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"HTTPS","marks":[{"type":"bold"}]},{"type":"text","text":" (avec le S) → c'est comme "},{"type":"text","text":"envoyer une lettre dans une enveloppe scellée","marks":[{"type":"bold"}]},{"type":"text","text":". Personne ne peut la lire pendant le trajet."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Le HTTPS repose sur ce qu'on appelle un "},{"type":"text","text":"certificat SSL/TLS","marks":[{"type":"bold"}]},{"type":"text","text":". C'est en quelque sorte la "},{"type":"text","text":"carte d'identité numérique","marks":[{"type":"bold"}]},{"type":"text","text":" du site, qui prouve aussi au visiteur qu'il est bien sur le bon site (et pas sur une copie pirate)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"⚠️ Ce qui peut arriver"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Un client se connecte au Wi-Fi gratuit d'un café et remplit le formulaire de contact du site. Un pirate à 3 tables de là "},{"type":"text","text":"lit en clair son nom, son email et son numéro de téléphone","marks":[{"type":"bold"}]},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Pire : sur un site de e-commerce sans HTTPS, le pirate intercepte directement les "},{"type":"text","text":"numéros de carte bancaire","marks":[{"type":"bold"}]},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Google affiche un gros message rouge "},{"type":"text","text":"\"Site non sécurisé\"","marks":[{"type":"bold"}]},{"type":"text","text":" aux visiteurs → ils fuient → vous perdez vos clients."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le site est "},{"type":"text","text":"déclassé","marks":[{"type":"bold"}]},{"type":"text","text":" dans les résultats Google (le HTTPS est un critère de référencement officiel depuis 2014)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🔍 Comment vérifier"}]},{"type":"paragraph","content":[{"type":"text","text":"Outil gratuit : ","marks":[{"type":"bold"}]},{"type":"text","text":"SSL Labs","marks":[{"type":"bold"},{"type":"link","attrs":{"href":"https://www.ssllabs.com/ssltest/","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" (la référence mondiale, utilisé par tous les pros)"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ouvrir "},{"type":"text","text":"https://www.ssllabs.com/ssltest/","marks":[{"type":"link","attrs":{"href":"https://www.ssllabs.com/ssltest/","target":"_blank","rel":"noopener noreferrer"}}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Taper l'adresse du site (ex : "},{"type":"text","text":"monsite.fr","marks":[{"type":"code"}]},{"type":"text","text":")"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cocher "},{"type":"text","text":"\"Do not show the results on the boards\"","marks":[{"type":"bold"}]},{"type":"text","text":" (pour ne pas afficher publiquement)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cliquer sur "},{"type":"text","text":"Submit","marks":[{"type":"bold"}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Attendre 1-2 minutes"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Lire la note (de A+ à F)"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Vérifications complémentaires :","marks":[{"type":"bold"}]}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Taper "},{"type":"text","text":"http://monsite.fr","marks":[{"type":"code"}]},{"type":"text","text":" dans le navigateur → ça doit "},{"type":"text","text":"automatiquement","marks":[{"type":"bold"}]},{"type":"text","text":" rediriger vers "},{"type":"text","text":"https://","marks":[{"type":"code"}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le cadenas doit être visible et fermé dans la barre d'adresse du navigateur"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cliquer sur le cadenas pour vérifier que le certificat est bien valide et pas expiré"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ La note minimum"}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — Note "},{"type":"text","text":"A","marks":[{"type":"bold"}]},{"type":"text","text":" minimum sur SSL Labs. On vise toujours le "},{"type":"text","text":"A+","marks":[{"type":"bold"}]},{"type":"text","text":"."}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — Toute connexion en HTTP doit être automatiquement redirigée en HTTPS."}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🛠️ Si problème"}]},{"type":"paragraph","content":[{"type":"text","text":"Le développeur active le certificat (Let's Encrypt = gratuit, intégré dans Vercel et la plupart des hébergeurs) et configure la redirection HTTP → HTTPS."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"2. Les serrures supplémentaires : les en-têtes de sécurité"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🤔 C'est quoi ?"}]},{"type":"paragraph","content":[{"type":"text","text":"Imaginez votre maison. Vous avez "},{"type":"text","text":"une porte d'entrée","marks":[{"type":"bold"}]},{"type":"text","text":", c'est bien. Mais une porte seule ne suffit pas : vous ajoutez "},{"type":"text","text":"un verrou multipoints, un judas, une chaîne de sûreté, une alarme","marks":[{"type":"bold"}]},{"type":"text","text":". Chacun protège contre un type d'intrusion différent."}]},{"type":"paragraph","content":[{"type":"text","text":"Sur un site web, c'est pareil. À côté du HTTPS (la porte), il y a "},{"type":"text","text":"6 ou 7 \"serrures\"","marks":[{"type":"bold"}]},{"type":"text","text":" invisibles qu'on appelle "},{"type":"text","text":"en-têtes de sécurité (security headers)","marks":[{"type":"bold"}]},{"type":"text","text":". Ce sont des instructions que le site envoie au navigateur du visiteur, du genre :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"\"Refuse de m'afficher si quelqu'un essaie de me copier dans une fausse fenêtre.\""}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"\"N'exécute pas de code venant d'ailleurs que de chez moi.\""}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"\"Force toujours la version sécurisée du site.\""}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Ces serrures sont "},{"type":"text","text":"gratuites","marks":[{"type":"bold"}]},{"type":"text","text":", "},{"type":"text","text":"invisibles pour l'utilisateur","marks":[{"type":"bold"}]},{"type":"text","text":", et leur seule absence fait fuir tous les auditeurs sécurité."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"⚠️ Ce qui peut arriver"}]},{"type":"paragraph","content":[{"type":"text","text":"Sans ces protections :"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Un pirate peut afficher votre site "},{"type":"text","text":"dans une fausse fenêtre invisible","marks":[{"type":"bold"}]},{"type":"text","text":", et quand le visiteur clique sur \"Acheter\", il clique en réalité sur \"Donner accès à mon compte\". On appelle ça le "},{"type":"text","text":"clickjacking","marks":[{"type":"bold"}]},{"type":"text","text":" (détournement de clic)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Du "},{"type":"text","text":"code malveillant","marks":[{"type":"bold"}]},{"type":"text","text":" peut être injecté depuis un autre site et s'exécuter chez vos visiteurs (vol de cookies, redirection vers des sites de phishing)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Un audit sécurité du client (avant qu'il vous paye le solde) "},{"type":"text","text":"vous descend en flammes","marks":[{"type":"bold"}]},{"type":"text","text":" : \"Aucun en-tête de sécurité configuré.\""}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🔍 Comment vérifier"}]},{"type":"paragraph","content":[{"type":"text","text":"Outil gratuit n°1 : ","marks":[{"type":"bold"}]},{"type":"text","text":"securityheaders.com","marks":[{"type":"bold"},{"type":"link","attrs":{"href":"https://securityheaders.com","target":"_blank","rel":"noopener noreferrer"}}]}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Ouvrir "},{"type":"text","text":"https://securityheaders.com","marks":[{"type":"link","attrs":{"href":"https://securityheaders.com","target":"_blank","rel":"noopener noreferrer"}}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Taper l'adresse du site"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cocher "},{"type":"text","text":"\"Hide results\"","marks":[{"type":"bold"}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cliquer sur "},{"type":"text","text":"Scan","marks":[{"type":"bold"}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Lire la note (de A+ à F) et la liste des en-têtes manquants"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Outil gratuit n°2 : ","marks":[{"type":"bold"}]},{"type":"text","text":"Mozilla Observatory","marks":[{"type":"bold"},{"type":"link","attrs":{"href":"https://developer.mozilla.org/en-US/observatory","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" (plus complet, recommandé par Mozilla)"}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Aller sur "},{"type":"text","text":"https://developer.mozilla.org/en-US/observatory","marks":[{"type":"link","attrs":{"href":"https://developer.mozilla.org/en-US/observatory","target":"_blank","rel":"noopener noreferrer"}}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Taper le site"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cliquer sur "},{"type":"text","text":"Scan","marks":[{"type":"bold"}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le rapport explique chaque ligne et donne des conseils"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ La note minimum"}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — Note "},{"type":"text","text":"A","marks":[{"type":"bold"}]},{"type":"text","text":" minimum sur securityheaders.com."}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟧 "},{"type":"text","text":"IMPORTANT","marks":[{"type":"bold"}]},{"type":"text","text":" — Note "},{"type":"text","text":"B+","marks":[{"type":"bold"}]},{"type":"text","text":" minimum sur Mozilla Observatory."}]}]},{"type":"paragraph","content":[{"type":"text","text":"Les en-têtes obligatoires que doit envoyer le site :","marks":[{"type":"bold"}]}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Strict-Transport-Security","marks":[{"type":"code"}]},{"type":"text","text":" — \"Force toujours la version HTTPS, même si l'utilisateur tape HTTP.\""}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Content-Security-Policy","marks":[{"type":"code"}]},{"type":"text","text":" — \"N'exécute que le code qui vient de moi, refuse tout le reste.\""}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"X-Content-Type-Options","marks":[{"type":"code"}]},{"type":"text","text":" — \"Ne laisse pas le navigateur deviner le type des fichiers, ça peut être dangereux.\""}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"X-Frame-Options","marks":[{"type":"code"}]},{"type":"text","text":" — \"Refuse d'être affiché dans une fenêtre invisible (anti-clickjacking).\""}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Referrer-Policy","marks":[{"type":"code"}]},{"type":"text","text":" — \"Ne donne pas trop d'infos sur d'où vient le visiteur.\""}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Permissions-Policy","marks":[{"type":"code"}]},{"type":"text","text":" — \"Désactive les fonctions du navigateur dont je n'ai pas besoin (caméra, micro, géoloc, etc.).\""}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🛠️ Si problème"}]},{"type":"paragraph","content":[{"type":"text","text":"Le développeur ajoute ces en-têtes en quelques minutes dans la configuration du site (fichier "},{"type":"text","text":"next.config.js","marks":[{"type":"code"}]},{"type":"text","text":" pour les sites Next.js, ou panneau Vercel/hébergeur)."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"3. Les mots de passe et les accès"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🤔 C'est quoi ?"}]},{"type":"paragraph","content":[{"type":"text","text":"Le mot de passe, c'est "},{"type":"text","text":"la clé","marks":[{"type":"bold"}]},{"type":"text","text":" de la maison. Mais "},{"type":"text","text":"80 % des piratages d'envergure en 2024","marks":[{"type":"bold"}]},{"type":"text","text":" ont commencé par un simple mot de passe volé (source : CNIL). Pourquoi ?"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les gens utilisent "},{"type":"text","text":"le même mot de passe partout","marks":[{"type":"bold"}]},{"type":"text","text":". Quand un site comme LinkedIn ou Adobe se fait pirater (ça arrive régulièrement), les pirates récupèrent des millions de couples email/mot de passe et les essaient ailleurs."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Les mots de passe sont "},{"type":"text","text":"trop simples","marks":[{"type":"bold"}]},{"type":"text","text":" (\"123456\", \"password\", le prénom des enfants). Un pirate met "},{"type":"text","text":"moins d'une seconde","marks":[{"type":"bold"}]},{"type":"text","text":" à les deviner avec un logiciel."}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"La solution moderne, c'est la "},{"type":"text","text":"double authentification (2FA / MFA)","marks":[{"type":"bold"}]},{"type":"text","text":". C'est comme "},{"type":"text","text":"ajouter un deuxième verrou","marks":[{"type":"bold"}]},{"type":"text","text":" : même si un voleur a la clé (le mot de passe), il lui manque encore le code reçu par téléphone (deuxième facteur)."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"⚠️ Ce qui peut arriver"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Un ancien employé du client garde son accès admin → un an plus tard, il se connecte et "},{"type":"text","text":"détruit le site par vengeance","marks":[{"type":"bold"}]},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le mot de passe admin est "},{"type":"text","text":"admin123","marks":[{"type":"code"}]},{"type":"text","text":" → un robot le trouve en quelques minutes et "},{"type":"text","text":"prend le contrôle total","marks":[{"type":"bold"}]},{"type":"text","text":"."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le client réutilise le même mot de passe que sur un forum piraté → un pirate "},{"type":"text","text":"se connecte directement","marks":[{"type":"bold"}]},{"type":"text","text":" au back-office."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🔍 Comment vérifier"}]},{"type":"paragraph","content":[{"type":"text","text":"Pas d'outil de scan automatique pour ça","marks":[{"type":"bold"}]},{"type":"text","text":", c'est une "},{"type":"text","text":"vérification organisationnelle","marks":[{"type":"bold"}]},{"type":"text","text":". À faire en checklist avec le client."}]},{"type":"paragraph","content":[{"type":"text","text":"La checklist accès & mots de passe :","marks":[{"type":"bold"}]}]},{"type":"taskList","content":[{"type":"taskItem","attrs":{"checked":false},"content":[{"type":"paragraph","content":[{"type":"text","text":"Aucun mot de passe par défaut","marks":[{"type":"bold"}]},{"type":"text","text":" n'est resté actif (admin/admin, root/root, etc.)"}]}]},{"type":"taskItem","attrs":{"checked":false},"content":[{"type":"paragraph","content":[{"type":"text","text":"Chaque personne a son propre compte","marks":[{"type":"bold"}]},{"type":"text","text":" (pas de compte partagé \"admin\" utilisé par 3 personnes)"}]}]},{"type":"taskItem","attrs":{"checked":false},"content":[{"type":"paragraph","content":[{"type":"text","text":"Double authentification activée","marks":[{"type":"bold"}]},{"type":"text","text":" sur tous les comptes critiques : Vercel, Supabase, Google Workspace, hébergeur, gestionnaire de domaine, GitHub, Stripe…"}]}]},{"type":"taskItem","attrs":{"checked":false},"content":[{"type":"paragraph","content":[{"type":"text","text":"Anciens employés / prestataires révoqués","marks":[{"type":"bold"}]},{"type":"text","text":" : aucun ancien collaborateur n'a encore accès"}]}]},{"type":"taskItem","attrs":{"checked":false},"content":[{"type":"paragraph","content":[{"type":"text","text":"Mots de passe stockés dans un coffre-fort numérique","marks":[{"type":"bold"}]},{"type":"text","text":" (1Password, Bitwarden, Dashlane) — jamais dans un fichier Excel, jamais par email"}]}]},{"type":"taskItem","attrs":{"checked":false},"content":[{"type":"paragraph","content":[{"type":"text","text":"Politique de mot de passe forte","marks":[{"type":"bold"}]},{"type":"text","text":" côté site : minimum 12 caractères, refus des mots de passe les plus piratés (utiliser la liste "},{"type":"text","text":"Have I Been Pwned","marks":[{"type":"link","attrs":{"href":"https://haveibeenpwned.com","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":")"}]}]},{"type":"taskItem","attrs":{"checked":false},"content":[{"type":"paragraph","content":[{"type":"text","text":"Principe du moindre privilège","marks":[{"type":"bold"}]},{"type":"text","text":" : chacun a uniquement les accès dont il a besoin (pas tout le monde admin)"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Outils utiles :","marks":[{"type":"bold"}]}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Have I Been Pwned","marks":[{"type":"link","attrs":{"href":"https://haveibeenpwned.com","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" — vérifier si une adresse email du client a déjà été compromise dans une fuite connue"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"1Password","marks":[{"type":"link","attrs":{"href":"https://1password.com","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":", "},{"type":"text","text":"Bitwarden","marks":[{"type":"link","attrs":{"href":"https://bitwarden.com","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" — coffres-forts numériques pour mots de passe"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Authy, Google Authenticator, Microsoft Authenticator — applis pour la double authentification"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ La note minimum"}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — Double authentification activée sur "},{"type":"text","text":"tous","marks":[{"type":"bold"}]},{"type":"text","text":" les comptes critiques."}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — Aucun mot de passe par défaut n'est encore actif."}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟧 "},{"type":"text","text":"IMPORTANT","marks":[{"type":"bold"}]},{"type":"text","text":" — Le client utilise un coffre-fort numérique pour ses mots de passe."}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🛠️ Si problème"}]},{"type":"paragraph","content":[{"type":"text","text":"Briefing client : on lui explique pourquoi c'est critique, on installe le coffre-fort avec lui, on active la 2FA ensemble."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"4. Les pirates qui essaient d'entrer : les 10 attaques les plus courantes"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🤔 C'est quoi ?"}]},{"type":"paragraph","content":[{"type":"text","text":"Une organisation mondiale appelée "},{"type":"text","text":"OWASP","marks":[{"type":"bold"}]},{"type":"text","text":" publie chaque 4 ans la liste des "},{"type":"text","text":"10 attaques les plus courantes","marks":[{"type":"bold"}]},{"type":"text","text":" contre les sites web. C'est la "},{"type":"text","text":"bible mondiale","marks":[{"type":"bold"}]},{"type":"text","text":" de la sécurité web. La dernière version, l'"},{"type":"text","text":"OWASP Top 10:2025","marks":[{"type":"bold"}]},{"type":"text","text":", est sortie fin 2025."}]},{"type":"paragraph","content":[{"type":"text","text":"Voici les 10 dans l'ordre, expliquées simplement avec une analogie :"}]},{"type":"paragraph","content":[{"type":"text","text":"1. Contrôles d'accès cassés (n°1 mondial — 3,73 % des sites touchés)","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Vous avez bien fermé la porte d'entrée à clé. Mais la fenêtre de la cuisine n'a pas de serrure, et tout le monde le sait. Un pirate peut rentrer par la fenêtre.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : un visiteur lambda peut accéder à des pages réservées aux admins juste en changeant l'adresse dans la barre URL."}]},{"type":"paragraph","content":[{"type":"text","text":"2. Mauvaise configuration (passé du n°5 au n°2)","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : La maison est bien construite, mais le constructeur a oublié de fermer la porte de garage. Et il a laissé les clés dessus.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : un compte admin avec le mot de passe par défaut, un fichier de config exposé publiquement, un message d'erreur qui révèle la structure de la base de données."}]},{"type":"paragraph","content":[{"type":"text","text":"3. Failles de la chaîne d'approvisionnement (NOUVEAU en 2025)","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Vous achetez une serrure réputée. Sauf que le fabricant s'est fait pirater, et tous ses clients ont la même copie de clé qui circule chez les voleurs.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : votre site utilise une bibliothèque de code (un \"ingrédient\") qui a été infectée par un pirate. Vous installez l'infection avec elle."}]},{"type":"paragraph","content":[{"type":"text","text":"4. Problèmes de chiffrement","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Vous gardez vos bijoux dans un coffre-fort, mais le coffre est en carton.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : les mots de passe des utilisateurs sont stockés en clair dans la base de données, ou les communications passent en HTTP au lieu de HTTPS."}]},{"type":"paragraph","content":[{"type":"text","text":"5. Injections (le grand classique, descendu du 3 au 5)","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Quelqu'un glisse un faux papier dans votre boîte aux lettres avec écrit \"facture impayée, donnez 1000 €\" — et votre comptable, sans vérifier, exécute l'ordre.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : un visiteur tape dans un formulaire un texte qui n'est pas un vrai texte mais une "},{"type":"text","text":"commande secrète","marks":[{"type":"bold"}]},{"type":"text","text":", et le site l'exécute aveuglément. Permet de voler toute la base de données (SQL injection) ou de pirater les visiteurs (XSS)."}]},{"type":"paragraph","content":[{"type":"text","text":"6. Conception non sécurisée","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : La maison a été construite sans plan, en mode \"on improvise\". Les murs ne sont pas porteurs, l'électricité passe à côté de la plomberie.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : le site n'a pas été pensé pour la sécurité dès le départ. Aucune rustine ne corrigera ça après coup."}]},{"type":"paragraph","content":[{"type":"text","text":"7. Failles d'authentification","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Le code de l'alarme est \"0000\". N'importe qui peut le deviner.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : pas de limite au nombre de tentatives de connexion (un robot peut tester 1 million de mots de passe), pas de double authentification, possibilité de se connecter en tant que quelqu'un d'autre."}]},{"type":"paragraph","content":[{"type":"text","text":"8. Problèmes d'intégrité des logiciels et des données","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Vous recevez un colis Amazon, mais l'emballage est ouvert et il y a des traces. Vous acceptez quand même sans vérifier.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : votre site télécharge automatiquement des mises à jour, mais ne vérifie pas si elles viennent vraiment du bon éditeur."}]},{"type":"paragraph","content":[{"type":"text","text":"9. Pas assez de surveillance et d'alertes","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Vous êtes cambriolé pendant les vacances. Quand vous rentrez 3 semaines plus tard, vous ne savez pas quand c'est arrivé ni ce qui a été pris. Aucune caméra, aucune alarme.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : le site se fait attaquer pendant des semaines avant que quelqu'un s'en rende compte. Pas de logs, pas d'alertes, pas de monitoring."}]},{"type":"paragraph","content":[{"type":"text","text":"10. Mauvaise gestion des erreurs (NOUVEAU en 2025)","marks":[{"type":"bold"}]},{"type":"text","text":"\n🏠 "},{"type":"text","text":"Analogie","marks":[{"type":"italic"}]},{"type":"text","text":" : Quand quelqu'un sonne avec un faux nom, votre porte ne se contente pas de rester fermée : elle affiche "},{"type":"text","text":"un plan détaillé de votre maison","marks":[{"type":"bold"}]},{"type":"text","text":" sur le paillasson.\n"},{"type":"text","text":"Concrètement","marks":[{"type":"italic"}]},{"type":"text","text":" : quand une erreur survient, le site affiche le code source, la structure de la base, le mot de passe... Cadeau pour le pirate."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"⚠️ Ce qui peut arriver"}]},{"type":"paragraph","content":[{"type":"text","text":"Les conséquences vont du "},{"type":"text","text":"vol massif de données","marks":[{"type":"bold"}]},{"type":"text","text":" (et l'amende RGPD qui va avec) à la "},{"type":"text","text":"prise de contrôle totale","marks":[{"type":"bold"}]},{"type":"text","text":" du site, en passant par la "},{"type":"text","text":"revente de la base clients","marks":[{"type":"bold"}]},{"type":"text","text":" sur le dark web."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🔍 Comment vérifier"}]},{"type":"paragraph","content":[{"type":"text","text":"Outil gratuit n°1 : ","marks":[{"type":"bold"}]},{"type":"text","text":"Sucuri SiteCheck","marks":[{"type":"bold"},{"type":"link","attrs":{"href":"https://sitecheck.sucuri.net","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" — Détecte les sites déjà infectés, les blacklists Google, et donne un premier diagnostic. Limite : ne fait que de la détection en surface."}]},{"type":"paragraph","content":[{"type":"text","text":"Outil gratuit n°2 : ","marks":[{"type":"bold"}]},{"type":"text","text":"Quttera","marks":[{"type":"bold"},{"type":"link","attrs":{"href":"https://quttera.com/website-malware-scanner","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" — Détecte les malwares connus."}]},{"type":"paragraph","content":[{"type":"text","text":"Outil semi-pro : ","marks":[{"type":"bold"}]},{"type":"text","text":"OWASP ZAP","marks":[{"type":"bold"},{"type":"link","attrs":{"href":"https://www.zaproxy.org","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" — Scanner gratuit, mais demande un développeur pour l'utiliser correctement (faux positifs nombreux)."}]},{"type":"paragraph","content":[{"type":"text","text":"Pour les projets sensibles → faire faire un vrai audit (pen test) :","marks":[{"type":"bold"}]}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cabinets français : Vaadata, Synacktiv, YesWeHack"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Plateformes : YesWeHack (bug bounty)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Coût : 3 000 à 15 000 € selon la taille du site"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ La note minimum"}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — Sucuri SiteCheck doit être "},{"type":"text","text":"clean","marks":[{"type":"bold"}]},{"type":"text","text":" (aucun malware détecté, aucune blacklist)."}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟧 "},{"type":"text","text":"IMPORTANT","marks":[{"type":"bold"}]},{"type":"text","text":" — Pour tout site qui traite des paiements ou des données sensibles : "},{"type":"text","text":"audit pen test externe","marks":[{"type":"bold"}]},{"type":"text","text":" avant la mise en production."}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🛠️ Si problème"}]},{"type":"paragraph","content":[{"type":"text","text":"Si Sucuri détecte quelque chose, "},{"type":"text","text":"arrêt immédiat","marks":[{"type":"bold"}]},{"type":"text","text":" du rendu : un site infecté ne se livre pas. Le développeur identifie la source, nettoie, et on relance les tests."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"5. Les pièces détachées du site : les mises à jour"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🤔 C'est quoi ?"}]},{"type":"paragraph","content":[{"type":"text","text":"Un site web moderne, c'est comme "},{"type":"text","text":"une voiture neuve assemblée à partir de pièces de centaines de fournisseurs différents","marks":[{"type":"bold"}]},{"type":"text","text":". On estime que "},{"type":"text","text":"80 % du code","marks":[{"type":"bold"}]},{"type":"text","text":" d'un site n'est pas écrit par votre développeur, mais par des bibliothèques externes (comme les pièces détachées d'une voiture)."}]},{"type":"paragraph","content":[{"type":"text","text":"Le problème ? "},{"type":"text","text":"Régulièrement","marks":[{"type":"bold"}]},{"type":"text","text":", on découvre qu'une de ces pièces a un défaut de fabrication (= une faille de sécurité). Le fournisseur sort un correctif. Si vous ne l'installez pas, vous "},{"type":"text","text":"roulez avec un airbag défectueux","marks":[{"type":"bold"}]},{"type":"text","text":"."}]},{"type":"paragraph","content":[{"type":"text","text":"L'OWASP a élevé ce risque à la "},{"type":"text","text":"3e place mondiale","marks":[{"type":"bold"}]},{"type":"text","text":" en 2025, sous le nom \"Failles de la chaîne d'approvisionnement logicielle\"."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"⚠️ Ce qui peut arriver"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cas WordPress","marks":[{"type":"bold"}]},{"type":"text","text":" (60 % des sites web mondiaux) : un plugin obsolète sur un seul site sur dix permet à un pirate de prendre le contrôle complet du site, et parfois du serveur entier. C'est la "},{"type":"text","text":"première cause de piratage","marks":[{"type":"bold"}]},{"type":"text","text":" sur WordPress."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Cas npm","marks":[{"type":"bold"}]},{"type":"text","text":" (l'écosystème JavaScript moderne) : en 2024-2025, plusieurs paquets très populaires ont été "},{"type":"text","text":"infectés par des pirates","marks":[{"type":"bold"}]},{"type":"text","text":" qui ont volé des cryptomonnaies aux utilisateurs."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"🔍 Comment vérifier"}]},{"type":"paragraph","content":[{"type":"text","text":"Pour les sites avec WordPress, Joomla, Drupal :","marks":[{"type":"bold"}]}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Le développeur lance un scan dans le back-office"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"WPScan","marks":[{"type":"link","attrs":{"href":"https://wpscan.com","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" — scanner gratuit dédié WordPress"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Sucuri","marks":[{"type":"link","attrs":{"href":"https://sitecheck.sucuri.net","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" — détection à distance"}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Pour les sites modernes (Next.js, React…) :","marks":[{"type":"bold"}]}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Commande à lancer dans le code : "},{"type":"text","text":"npm audit","marks":[{"type":"code"}]}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Service en ligne : "},{"type":"text","text":"Snyk","marks":[{"type":"link","attrs":{"href":"https://snyk.io","target":"_blank","rel":"noopener noreferrer"}}]},{"type":"text","text":" (gratuit jusqu'à un certain volume)"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Dependabot","marks":[{"type":"bold"}]},{"type":"text","text":" activé sur GitHub (gratuit) → propose automatiquement les correctifs sous forme de \"Pull Requests\""}]}]}]},{"type":"paragraph","content":[{"type":"text","text":"Sur Snyk :","marks":[{"type":"bold"}]}]},{"type":"orderedList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Connecter le compte GitHub"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Sélectionner le repo du projet"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Lancer le scan"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Lire le nombre de vulnérabilités par niveau (Low, Medium, High, Critical)"}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"✅ La note minimum"}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟥 "},{"type":"text","text":"VITAL","marks":[{"type":"bold"}]},{"type":"text","text":" — "},{"type":"text","text":"Aucune","marks":[{"type":"bold"}]},{"type":"text","text":" vulnérabilité de niveau "},{"type":"text","text":"High","marks":[{"type":"bold"}]},{"type":"text","text":" ou "},{"type":"text","text":"Critical","marks":[{"type":"bold"}]},{"type":"text","text":" au moment du rendu."}]}]},{"type":"blockquote","content":[{"type":"paragraph","content":[{"type":"text","text":"🟧 "},{"type":"text","text":"IMPORTANT","marks":[{"type":"bold"}]},{"type":"text","text":" — "},{"type":"text","text":"Aucune","marks":[{"type":"bold"}]},{"type":"text","text":" vulnérabilité de niveau "},{"type":"text","text":"Medium","marks":[{"type":"bold"}]},{"type":"text","text":" sans justification é